  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--card", theme.colors.background);
  root.style.setProperty("--popover", theme.colors.background);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);
  document.documentElement.classList.toggle("dark", theme.isDark);
