import { useCallback, useSyncExternalStore } from "react";
import { DEFAULT_THEME_ID, getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:color-theme";

let listeners: Array<() => void> = [];
let lastThemeId: string | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
}

function applyColorTheme(theme: Theme) {
  const root = document.documentElement;

  // Apply CSS custom properties so downstream CSS/components can reference them
  root.style.setProperty("--theme-background", theme.colors.background);
  root.style.setProperty("--theme-foreground", theme.colors.foreground);
  root.style.setProperty("--theme-accent", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);

  if (theme.fontFamily !== undefined) {
    root.style.setProperty("--theme-font-family", theme.fontFamily);
  } else {
    root.style.removeProperty("--theme-font-family");
  }

  if (theme.fontSize !== undefined) {
    root.style.setProperty("--theme-font-size", theme.fontSize);
  } else {
    root.style.removeProperty("--theme-font-size");
  }
}

// Apply immediately on module load to prevent flash
applyColorTheme(getTheme(getStoredId()));

function getSnapshot(): string {
  const id = getStoredId();
  if (lastThemeId === id) return lastThemeId;
  lastThemeId = id;
  return lastThemeId;
}

function getServerSnapshot(): string {
  return DEFAULT_THEME_ID;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyColorTheme(getTheme(getStoredId()));
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

/**
 * Access and change the active color theme.
 *
 * - `theme` — the currently active {@link Theme} object
 * - `setTheme(id)` — persist a new theme by id and apply it immediately
 * - `availableThemes` — all built-in themes, ordered for display
 */
export function useColorTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
  const theme = getTheme(themeId);

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyColorTheme(next);
    lastThemeId = next.id;
    emitChange();
  }, []);

  return { theme, setTheme, availableThemes: listThemes() } as const;
}

