import { useColorTheme } from "../hooks/useColorTheme";

/**
 * Three color swatches (background, foreground, accent) used to preview a
 * theme without applying it.
 */
function ThemeSwatches({
  background,
  foreground,
  accent,
}: {
  background: string;
  foreground: string;
  accent: string;
}) {
  return (
    <span
      className="flex shrink-0 items-center gap-0.5 overflow-hidden rounded border border-border"
      aria-hidden="true"
    >
      <span
        className="h-4 w-4"
        style={{ backgroundColor: background }}
        title="Background"
      />
      <span
        className="h-4 w-2.5"
        style={{ backgroundColor: foreground }}
        title="Foreground"
      />
      <span
        className="h-4 w-2.5"
        style={{ backgroundColor: accent }}
        title="Accent"
      />
    </span>
  );
}

/**
 * Radio-group that lets the user pick a named color theme.
 * Mirrors the visual style of the existing Appearance section in Settings.
 */
export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useColorTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme preference">
      {availableThemes.map((option) => {
        const selected = theme.id === option.id;
        return (
          <button
            key={option.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent"
            }`}
            onClick={() => setTheme(option.id)}
          >
            <span className="flex items-center gap-3">
              <ThemeSwatches
                background={option.colors.background}
                foreground={option.colors.foreground}
                accent={option.colors.accent}
              />
              <span className="flex flex-col">
                <span className="text-sm font-medium">{option.name}</span>
                <span className="text-xs">
                  {option.isDark ? "Dark" : "Light"} color palette
                </span>
              </span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

