}

body {
  font-family:
    "DM Sans",
    -apple-system,
    BlinkMacSystemFont,
    "Segoe UI",
    system-ui,
    sans-serif;
  margin: 0;
  padding: 0;
  min-height: 100vh;
}

html,
body,
#root {
  height: 100%;
  width: 100%;
  max-width: 100%;
  overflow-y: hidden;
  overflow-x: hidden;
  overflow-x: clip;
  overscroll-behavior-y: none;
}

body::after {
  content: "";
  position: fixed;
  inset: 0;
  pointer-events: none;
  opacity: 0.035;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
  background-repeat: repeat;
  background-size: 256px 256px;
}

pre,
code,
textarea,
input {
  font-family: "SF Mono", "SFMono-Regular", Consolas, "Liberation Mono", Menlo, monospace;
}

/* Window drag region (frameless titlebar) */
.drag-region {
  -webkit-app-region: drag;
}

.drag-region button,
.drag-region input,
.drag-region textarea,
.drag-region select,
.drag-region a {
  -webkit-app-region: no-drag;
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: rgba(0, 0, 0, 0.15);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(0, 0, 0, 0.25);
}

.dark ::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.1);
}

.dark ::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.18);
}

.turn-chip-strip {
  scrollbar-width: none;
  -ms-overflow-style: none;
  overscroll-behavior-x: contain;
}

.turn-chip-strip::-webkit-scrollbar {
  display: none;
}

/* Terminal drawer scrollbar parity with chat */
.thread-terminal-drawer .xterm .xterm-scrollable-element > .scrollbar.vertical {
  width: 6px !important;
}

.thread-terminal-drawer .xterm .xterm-scrollable-element > .scrollbar > .slider {
  border-radius: 3px;
}

.thread-terminal-drawer .xterm .xterm-scrollable-element > .scrollbar.vertical > .slider {
  width: 6px !important;
  left: 0 !important;
}

/* Reasoning select -- clickable label surface */
label:has(> select#reasoning-effort) {
  position: relative;
}
label:has(> select#reasoning-effort) select {
  position: absolute;
  inset: 0;
  opacity: 0;
  cursor: pointer;
  width: 100%;
  height: 100%;
}

/* Chat markdown rendering */
.chat-markdown {
  min-width: 0;
  overflow-wrap: anywhere;
  word-break: break-word;
}

.chat-markdown > :first-child {
  margin-top: 0;
}

.chat-markdown > :last-child {
  margin-bottom: 0;
}

.chat-markdown p,
.chat-markdown ul,
.chat-markdown ol,
.chat-markdown blockquote,
.chat-markdown pre,
.chat-markdown table {
  margin: 0.65rem 0;
}

.chat-markdown ul {
  padding-left: 1.25rem;
  list-style-type: disc;
}

.chat-markdown ol {
  padding-left: 1.25rem;
  list-style-type: decimal;
}

.chat-markdown ul ul {
  list-style-type: circle;
}

.chat-markdown ul ul ul {
  list-style-type: square;
}

.chat-markdown ol ol {
  list-style-type: lower-alpha;
}

.chat-markdown ol ol ol {
  list-style-type: lower-roman;
}

.chat-markdown li + li {
  margin-top: 0.25rem;
}

.chat-markdown a {
  color: var(--info-foreground);
  text-decoration: underline;
  text-decoration-color: color-mix(in srgb, var(--info-foreground) 40%, transparent);
}

.chat-markdown a:hover {
  opacity: 0.8;
}

.chat-markdown blockquote {
  border-left: 2px solid var(--border);
  padding-left: 0.8rem;
  color: var(--muted-foreground);
}

.chat-markdown :not(pre) > code {
  border: 1px solid var(--border);
  border-radius: 0.375rem;
  background: var(--muted);
  padding: 0.1rem 0.35rem;
  color: var(--foreground);
  font-size: 0.75rem;
}

.chat-markdown pre {
  max-width: 100%;
  overflow-x: auto;
  border: 1px solid var(--border);
  border-radius: 0.75rem;
  background: var(--muted);
  padding: 0.8rem 0.9rem;
}

.chat-markdown pre code {
  border: none;
  background: transparent;
  padding: 0;
  line-height: 1.5;
  font-size: 0.875rem;
}

.chat-markdown .chat-markdown-codeblock {
  position: relative;
  margin: 0.65rem 0;
}

.chat-markdown .chat-markdown-codeblock pre {
  margin: 0;
}

.chat-markdown .chat-markdown-copy-button {
  position: absolute;
  top: 0.5rem;
  right: 0.5rem;
  z-index: 1;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: 1.5rem;
  width: 1.5rem;
  border-radius: 0.375rem;
  border: 1px solid var(--border);
  background: color-mix(in srgb, var(--background) 82%, transparent);
  color: var(--muted-foreground);
  opacity: 0;
  pointer-events: none;
  transition:
    opacity 120ms ease,
    color 120ms ease,
    border-color 120ms ease;
}

.chat-markdown .chat-markdown-codeblock:hover .chat-markdown-copy-button,
.chat-markdown .chat-markdown-codeblock:focus-within .chat-markdown-copy-button {
  opacity: 1;
  pointer-events: auto;
}

.chat-markdown .chat-markdown-copy-button:hover {
  color: var(--foreground);
  border-color: color-mix(in srgb, var(--border) 70%, var(--foreground));
}

.chat-markdown .chat-markdown-shiki .shiki {
  background: color-mix(in srgb, var(--muted) 78%, var(--background)) !important;
}

.chat-markdown table {
  width: 100%;
  border-collapse: collapse;
}

.chat-markdown th,
.chat-markdown td {
  border: 1px solid var(--border);
  padding: 0.35rem 0.45rem;
  text-align: left;
}

/* Diffs theme bridge (match diff surfaces to app palette) */
.diff-panel-viewport {
  background: color-mix(in srgb, var(--background) 94%, var(--card));
}

.diff-render-file {
  border: 1px solid var(--border);
  border-radius: 0.5rem;
  overflow: clip;
  background: color-mix(in srgb, var(--card) 92%, var(--background));
}

/**
 * Named color palette for a T3 Code color theme.
 * All color values are valid CSS color strings.
 */
export interface ThemeColors {
  /** Page / app background */
  readonly background: string;
  /** Default text color */
  readonly foreground: string;
  /** Interactive highlight / brand color */
  readonly accent: string;
  /** Sidebar background */
  readonly sidebar: string;
  /** Code editor pane background */
  readonly editor: string;
  /** Integrated terminal background */
  readonly terminal: string;
  /** Status bar background */
  readonly statusBar: string;
}

/**
 * A complete color theme definition.
 */
export interface Theme {
  /** Unique, stable identifier (e.g. "t3-dark") */
  readonly id: string;
  /** Human-readable display name */
  readonly name: string;
  /** Color palette for this theme */
  readonly colors: ThemeColors;
  /**
   * CSS font-family stack applied to the whole UI.
   * If undefined, the app's default font stack is used.
   */
  readonly fontFamily?: string;
  /**
   * Base font size in pixels (number) or any valid CSS font-size string.
   * If undefined, the app's default font size is used.
   */
  readonly fontSize?: string;
  /**
   * Whether this theme is a dark theme.
   * When true the `.dark` CSS class is added to `<html>` so that
   * Tailwind dark-variant utilities apply correctly.
   */
  readonly isDark: boolean;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

const T3_DARK: Theme = {
  id: "t3-dark",
  name: "T3 Dark",
  isDark: true,
  colors: {
    background: "#0d0d0f",
    foreground: "#f0f0f0",
    accent: "oklch(0.588 0.217 264)",
    sidebar: "#111115",
    editor: "#0d0d0f",
    terminal: "#090a0c",
    statusBar: "#111115",
  },
};

const T3_LIGHT: Theme = {
  id: "t3-light",
  name: "T3 Light",
  isDark: false,
  colors: {
    background: "#ffffff",
    foreground: "#1a1a1a",
    accent: "oklch(0.488 0.217 264)",
    sidebar: "#f5f5f5",
    editor: "#ffffff",
    terminal: "#fafafa",
    statusBar: "#f0f0f0",
  },
};

const T3_MIDNIGHT: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  isDark: true,
  colors: {
    background: "#0f1117",
    foreground: "#e2e8f0",
    accent: "#7c3aed",
    sidebar: "#13151e",
    editor: "#0f1117",
    terminal: "#0a0b10",
    statusBar: "#13151e",
  },
};

const BUILT_IN_THEMES: readonly Theme[] = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];

const THEME_MAP: ReadonlyMap<string, Theme> = new Map(
  BUILT_IN_THEMES.map((t) => [t.id, t]),
);

/** Default theme id applied when no preference has been stored. */
export const DEFAULT_THEME_ID = "t3-dark";

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Return the theme with the given `id`.
 * Falls back to the default theme when `id` is unknown or omitted.
 */
export function getTheme(id?: string): Theme {
  if (id !== undefined) {
    const found = THEME_MAP.get(id);
    if (found !== undefined) return found;
  }
  // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
  return THEME_MAP.get(DEFAULT_THEME_ID)!;
}

/**
 * Return an ordered list of all available built-in themes.
 */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

